package runnables

import (
	"context"

	"sigs.k8s.io/controller-runtime/pkg/manager"
)

// Leader is a Runnable that needs to be run only when the current instance is the leader.
type Leader struct {
	manager.Runnable
}

var (
	_ manager.LeaderElectionRunnable = &Leader{}
	_ manager.Runnable               = &Leader{}
)

func (r *Leader) NeedLeaderElection() bool {
	return true
}

// LeaderOrNonLeader is a Runnable that needs to be run regardless of whether the current instance is the leader.
type LeaderOrNonLeader struct {
	manager.Runnable
}

var (
	_ manager.LeaderElectionRunnable = &LeaderOrNonLeader{}
	_ manager.Runnable               = &LeaderOrNonLeader{}
)

func (r *LeaderOrNonLeader) NeedLeaderElection() bool {
	return false
}

// CallFunctionsAfterBecameLeader is a Runnable that will call the given functions when the current instance becomes
// the leader.
type CallFunctionsAfterBecameLeader struct {
	enableFunctions []func(context.Context)
}

var (
	_ manager.LeaderElectionRunnable = &CallFunctionsAfterBecameLeader{}
	_ manager.Runnable               = &CallFunctionsAfterBecameLeader{}
)

// NewCallFunctionsAfterBecameLeader creates a new CallFunctionsAfterBecameLeader Runnable.
func NewCallFunctionsAfterBecameLeader(
	enableFunctions []func(context.Context),
) *CallFunctionsAfterBecameLeader {
	return &CallFunctionsAfterBecameLeader{
		enableFunctions: enableFunctions,
	}
}

func (j *CallFunctionsAfterBecameLeader) Start(ctx context.Context) error {
	for _, f := range j.enableFunctions {
		f(ctx)
	}

	return nil
}

func (j *CallFunctionsAfterBecameLeader) NeedLeaderElection() bool {
	return true
}

package events

import (
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/controller-runtime/pkg/client"

	ngftypes "github.com/nginx/nginx-gateway-fabric/v2/internal/framework/types"
)

// EventBatch is a batch of events to be handled at once.
type EventBatch []any

// UpsertEvent represents upserting a resource.
type UpsertEvent struct {
	// Resource is the resource that is being upserted.
	Resource client.Object
}

// DeleteEvent representing deleting a resource.
type DeleteEvent struct {
	// Type is the resource type. For example, if the event is for *v1.HTTPRoute, pass &v1.HTTPRoute{} as Type.
	Type ngftypes.ObjectType
	// NamespacedName is the namespace & name of the deleted resource.
	NamespacedName types.NamespacedName
}

// WAFBundleReconcileEvent is injected by the WAF poller manager when a bundle that was previously
// unavailable has been successfully fetched for the first time.
// It signals the event handler to re-reconcile the affected policy so the Gateway config push proceeds.
type WAFBundleReconcileEvent struct {
	// PolicyNsName is the namespace/name of the WAFPolicy whose bundle is now available.
	PolicyNsName types.NamespacedName
}

package runnables

import (
	"context"
	"time"

	"github.com/go-logr/logr"
	"k8s.io/apimachinery/pkg/util/wait"
	"sigs.k8s.io/controller-runtime/pkg/manager"
)

// CronJobConfig is the configuration for a cronjob.
type CronJobConfig struct {
	// Worker is the function that will be run for every cronjob iteration.
	Worker func(context.Context)
	// ReadyCh delays the start of the job until the channel is closed.
	ReadyCh <-chan struct{}
	// Logger is the logger.
	Logger logr.Logger
	// Period defines the period of the cronjob. The cronjob will run every Period.
	Period time.Duration
	// JitterFactor sets the jitter for the cronjob. If positive, the period is jittered before every
	// run of the worker. If jitterFactor is not positive, the period is unchanged and not jittered.
	JitterFactor float64
}

// CronJob periodically runs a worker function.
type CronJob struct {
	cfg CronJobConfig
}

// NewCronJob creates a new cronjob.
func NewCronJob(cfg CronJobConfig) *CronJob {
	return &CronJob{
		cfg: cfg,
	}
}

// Start starts the cronjob.
// Implements controller-runtime manager.Runnable.
func (j *CronJob) Start(ctx context.Context) error {
	select {
	case <-j.cfg.ReadyCh:
	case <-ctx.Done():
		j.cfg.Logger.Info("Context canceled, failed to start cronjob")
		return ctx.Err()
	}

	j.cfg.Logger.Info("Starting cronjob")

	sliding := true // This means the period with jitter will be calculated after each worker call.

	wait.JitterUntilWithContext(ctx, j.cfg.Worker, j.cfg.Period, j.cfg.JitterFactor, sliding)

	j.cfg.Logger.Info("Stopping cronjob")
	return nil
}

var _ manager.Runnable = &CronJob{}

package dataplane

import (
	"sort"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/ngfsort"
)

// sortPathRules sorts path rules by descending path length so that longer (more specific) paths appear first
// in the generated NGINX config. This is critical for regex locations where NGINX uses config-file order
// (first match wins). For exact and prefix locations, NGINX resolves matches by its own algorithm regardless
// of config order, so reordering them has no behavioral impact.
func sortPathRules(pathRules []PathRule) {
	sort.SliceStable(pathRules, func(i, j int) bool {
		if len(pathRules[i].Path) != len(pathRules[j].Path) {
			return len(pathRules[i].Path) > len(pathRules[j].Path)
		}
		if pathRules[i].Path != pathRules[j].Path {
			return pathRules[i].Path < pathRules[j].Path
		}
		// PathType string values sort in desired order: exact < prefix < regularExpression
		return pathRules[i].PathType < pathRules[j].PathType
	})
}

func sortMatchRules(matchRules []MatchRule) {
	// stable sort is used so that the order of matches (as defined in each Route rule) is preserved
	// this is important, because the winning match is the first match to win.
	sort.SliceStable(
		matchRules, func(i, j int) bool {
			return higherPriority(matchRules[i], matchRules[j])
		},
	)
}

/*
Returns true if rule1 has a higher priority than rule2.

From the spec:
Precedence must be given to the Rule with the largest number of (Continuing on ties):
(HTTPRoute)
- Characters in a matching non-wildcard hostname.
- Characters in a matching hostname.
- Characters in a matching path.
- Method match.
- Header matches.
- Query param matches.
or
(GRPCRoute)
- Characters in a matching non-wildcard hostname.
- Characters in a matching hostname.
- Characters in a matching service.
- Characters in a matching method.
- Header matches.

If ties still exist across multiple Routes, matching precedence MUST be determined in order of the following criteria,
continuing on ties:
- The oldest Route based on creation timestamp.
- The Route appearing first in alphabetical order by “{namespace}/{name}”.

If ties still exist within the Route that has been given precedence,
matching precedence MUST be granted to the first matching rule meeting the above criteria.

higherPriority will determine precedence by comparing len(headers), len(query parameters), creation timestamp,
and namespace name. It gives higher priority to rules with a method match. The other criteria are handled by NGINX.
For GRPCRoute rules, match.Method and match.QueryParams are always nil/ 0 len. Our representation combines service
and method into a path so that we perform "characters in a matching path" for GRPCRoute.
*/
func higherPriority(rule1, rule2 MatchRule) bool {
	// Compare if a method exists on one of the matches but not the other.
	// The match with the method specified wins.
	if rule1.Match.Method != nil && rule2.Match.Method == nil {
		return true
	}
	if rule2.Match.Method != nil && rule1.Match.Method == nil {
		return false
	}

	// Compare the number of header matches.
	// The match with the largest number of header matches wins.
	l1 := len(rule1.Match.Headers)
	l2 := len(rule2.Match.Headers)

	if l1 != l2 {
		return l1 > l2
	}
	// If the number of headers is equal then compare the number of query param matches.
	// The match with the most query param matches wins.
	l1 = len(rule1.Match.QueryParams)
	l2 = len(rule2.Match.QueryParams)

	if l1 != l2 {
		return l1 > l2
	}

	// If still tied, compare the object meta of the two routes.
	return ngfsort.LessObjectMeta(rule1.Source, rule2.Source)
}

package events

import (
	"context"
	"fmt"

	apierrors "k8s.io/apimachinery/pkg/api/errors"
	"k8s.io/apimachinery/pkg/api/meta"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/controller-runtime/pkg/client"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/kubernetes"
)

//counterfeiter:generate . FirstEventBatchPreparer

// FirstEventBatchPreparer prepares the first batch of events to be processed by the EventHandler.
// The first batch includes the UpsertEvents for all relevant resources in the cluster.
type FirstEventBatchPreparer interface {
	// Prepare prepares the first event batch.
	Prepare(ctx context.Context) (EventBatch, error)
}

// EachListItemFunc lists each item of a client.ObjectList.
// It is from k8s.io/apimachinery/pkg/api/meta.
type EachListItemFunc func(obj runtime.Object, fn func(runtime.Object) error) error

// FirstEventBatchPreparerImpl is an implementation of FirstEventBatchPreparer.
type FirstEventBatchPreparerImpl struct {
	reader       kubernetes.Reader
	eachListItem EachListItemFunc
	objects      []client.Object
	objectLists  []client.ObjectList
}

// NewFirstEventBatchPreparerImpl creates a new FirstEventBatchPreparerImpl.
// objects and objectList specify which resources will be included in the first batch.
// For each object from objects, FirstEventBatchPreparerImpl will get the corresponding resource from the reader.
// The object must specify its namespace (if any) and name.
// For each list from objectLists, FirstEventBatchPreparerImpl will list the resources of the corresponding type from
// the reader.
func NewFirstEventBatchPreparerImpl(
	reader kubernetes.Reader,
	objects []client.Object,
	objectLists []client.ObjectList,
) *FirstEventBatchPreparerImpl {
	return &FirstEventBatchPreparerImpl{
		reader:       reader,
		objects:      objects,
		objectLists:  objectLists,
		eachListItem: meta.EachListItem,
	}
}

// SetEachListItem sets the EachListItemFunc function.
// Used for unit testing.
func (p *FirstEventBatchPreparerImpl) SetEachListItem(eachListItem EachListItemFunc) {
	p.eachListItem = eachListItem
}

func (p *FirstEventBatchPreparerImpl) Prepare(ctx context.Context) (EventBatch, error) {
	total := 0

	for _, list := range p.objectLists {
		if err := p.reader.List(ctx, list); err != nil {
			return nil, err
		}

		total += meta.LenList(list)
	}

	// If some of p.objects don't exist, they will not be added to the batch. In that case, the capacity will be greater
	// than the length, but it is OK, because len(p.objects) is small.
	batch := make([]any, 0, total+len(p.objects))

	for _, obj := range p.objects {
		key := types.NamespacedName{Namespace: obj.GetNamespace(), Name: obj.GetName()}

		if err := p.reader.Get(ctx, key, obj); err != nil {
			if !apierrors.IsNotFound(err) {
				return nil, err
			}
		} else {
			batch = append(batch, &UpsertEvent{Resource: obj})
		}
	}

	// Note: the order of the events doesn't matter.

	for _, list := range p.objectLists {
		err := p.eachListItem(list, func(object runtime.Object) error {
			clientObj, ok := object.(client.Object)
			if !ok {
				return fmt.Errorf("cannot cast %T to client.Object", object)
			}
			batch = append(batch, &UpsertEvent{Resource: clientObj})
			return nil
		})
		if err != nil {
			return nil, err
		}
	}

	return batch, nil
}

	firstBatchPreparer := events.NewFirstEventBatchPreparerImpl(mgr.GetCache(), objects, objectLists)
	eventLoop := events.NewEventLoop(
		eventCh,
		cfg.Logger.WithName("eventLoop"),
		eventHandler,
		firstBatchPreparer,
	)

	if err = mgr.Add(&runnables.LeaderOrNonLeader{Runnable: eventLoop}); err != nil {
		return fmt.Errorf("cannot register event loop: %w", err)
	}

	if err = mgr.Add(runnables.NewCallFunctionsAfterBecameLeader([]func(context.Context){
		groupStatusUpdater.Enable,
		nginxProvisioner.Enable,
		eventHandler.enable,
	})); err != nil {
		return fmt.Errorf("cannot register functions that get called after Pod becomes leader: %w", err)
	}

	if err = registerTelemetry(cfg, mgr, processor, eventHandler, healthChecker); err != nil {
		return err
	}

	cfg.Logger.Info("Starting manager")
	go func() {
		<-ctx.Done()
		cfg.Logger.Info("Shutting down")
	}()

	return mgr.Start(ctx)
}

// createMetricsCollector creates a handler metrics collector and registers it with the Prometheus registry if enabled.
func createMetricsCollector(cfg config.Config) handlerMetricsCollector {
	if !cfg.MetricsConfig.Enabled {
		return collectors.NewControllerNoopCollector()
	}

	constLabels := map[string]string{"class": cfg.GatewayClassName}

	handlerCollector := collectors.NewControllerCollector(constLabels)
	metrics.Registry.MustRegister(handlerCollector)

	return handlerCollector
}

// createAgentServices creates the NGINX agent updater and gRPC server, and registers the server with the manager.
func createAgentServices(
	cfg config.Config,
	mgr manager.Manager,
	statusQueue *status.Queue,
) (*agent.NginxUpdaterImpl, error) {
	resetConnChan := make(chan struct{})
	nginxUpdater := agent.NewNginxUpdater(
		cfg.Logger.WithName("nginxUpdater"),
		mgr.GetAPIReader(),
		statusQueue,
		resetConnChan,
		cfg.Plus,
	)

	tokenAudience := fmt.Sprintf(
		"%s.%s.svc",
		cfg.GatewayPodConfig.ServiceName,
		cfg.GatewayPodConfig.Namespace,
	)

	grpcServer := agentgrpc.NewServer(
		cfg.Logger.WithName("agentGRPCServer"),
		grpcServerPort,
		[]func(*grpc.Server){
			nginxUpdater.CommandService.Register,
			nginxUpdater.FileService.Register,
		},
		mgr.GetClient(),
		tokenAudience,
		resetConnChan,
	)

	if err := mgr.Add(&runnables.LeaderOrNonLeader{Runnable: grpcServer}); err != nil {
		return nil, fmt.Errorf("cannot register grpc server: %w", err)
	}

	return nginxUpdater, nil
}

